#include <chrono>
#include <cmath>
#include <cstdio>
#include <cstdlib>
#include <iostream>
#include <iomanip>
#include <limits>
#include <utility>
#include <omp.h>

#define N 2048
#define IDX(i, j) ((i) + (j) * N)

static constexpr float PI_F = 3.14159265358979323846f;

void initialize_data(float* f) {
  for (int j = 0; j < N; ++j) {
    for (int i = 0; i < N; ++i) {
      if (i == 0 || i == N - 1) {
        f[IDX(i, j)] = sinf(j * 2.0f * PI_F / (N - 1));
      } else if (j == 0 || j == N - 1) {
        f[IDX(i, j)] = sinf(i * 2.0f * PI_F / (N - 1));
      } else {
        f[IDX(i, j)] = 0.0f;
      }
    }
  }
}

int main() {
  auto start_time = std::chrono::steady_clock::now();

  const size_t bytes = static_cast<size_t>(N) * static_cast<size_t>(N) * sizeof(float);

  float* f = (float*)aligned_alloc(64, bytes);
  float* f_old = (float*)aligned_alloc(64, bytes);

  initialize_data(f);
  initialize_data(f_old);

  int host = omp_get_initial_device();
  int dev = omp_get_default_device();

  float* d_f = (float*)omp_target_alloc(bytes, dev);
  float* d_f_old = (float*)omp_target_alloc(bytes, dev);

  omp_target_memcpy(d_f, f, bytes, 0, 0, dev, host);
  omp_target_memcpy(d_f_old, f_old, bytes, 0, 0, dev, host);

  float* d_f_alloc = d_f;
  float* d_f_old_alloc = d_f_old;

  float error = std::numeric_limits<float>::max();
  const float tolerance = 1.e-5f;

  const int max_iters = 10000;
  int num_iters = 0;

  auto start = std::chrono::steady_clock::now();

  while (tolerance < error && max_iters > num_iters) {
    float error_sum = 0.0f;

    float* curr = d_f;
    float* prev = d_f_old;

    #pragma omp target teams distribute parallel for collapse(2) is_device_ptr(curr, prev) reduction(+:error_sum)
    for (int j = 1; j <= N - 2; ++j) {
      for (int i = 1; i <= N - 2; ++i) {
        curr[IDX(i, j)] = 0.25f * (prev[IDX(i + 1, j)] +
                                   prev[IDX(i - 1, j)] +
                                   prev[IDX(i, j + 1)] +
                                   prev[IDX(i, j - 1)]);
        float df = curr[IDX(i, j)] - prev[IDX(i, j)];
        error_sum += df * df;
      }
    }

    std::swap(d_f, d_f_old);

    error = sqrtf(error_sum / (N * N));

    if (0 == num_iters % 1000) {
      std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
    }

    ++num_iters;
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

  if (tolerance >= error && max_iters > num_iters) {
    std::cout << "PASS" << std::endl;
  } else {
    std::cout << "FAIL" << std::endl;
    omp_target_free(d_f_alloc, dev);
    omp_target_free(d_f_old_alloc, dev);
    free(f);
    free(f_old);
    return -1;
  }

  omp_target_free(d_f_alloc, dev);
  omp_target_free(d_f_old_alloc, dev);
  free(f);
  free(f_old);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}
